SELECT DISTINCT SP.TBL_SO_P_ID AS TBL_RETURN_INBOUND_ID, SP.TBL_SO_M_ID, ISNULL(SP.IS_OUTBOUND_TARGET, 'Y') AS OUTBOUND_TARGET_YN, ISNULL(SP.YONGIN_INBOUNDED, 'N') AS INBOUND_YN, SP.YONGIN_INBOUND_DT AS INBOUND_DT, SP.YONGIN_INBOUND_REMARK AS INBOUND_REMARK, ISNULL(SP.AGENCY_OUTBOUNDED, 'N') AS OUTBOUND_YN, SP.AGENCY_OUTBOUND_DT AS OUTBOUND_DT, SP.AGENCY_OUTBOUND_REMARK AS OUTBOUND_REMARK, DC.DC_NM, SM.SO_NO, SM.REF_SO_NO, DBO.F_COL_NM('A', 'COMM', 'SO_ORDR_TYPE', SM.SO_TYPE) AS SO_TYPE_NM, DBO.F_COL_NM('A', 'COMM', 'SO_STAT_CD', SM.SO_STAT_CD) AS SO_STAT_CD_NM, SM.DLVY_CNFM_DT, UM.USER_NM AS INST_ER, AG.AGNT_NM, SM.ACPT_ER, SP.PROD_CD, SP.PROD_NM, SP.QTY AS RETURN_QTY, SP.YONGIN_INBOUND_USER AS INBOUND_USER, SP.AGENCY_OUTBOUND_USER AS OUTBOUND_USER, SM.POST_CD, SM.ADDR1, SM.ACPT_TEL1, SM.SAVE_TIME, SM.DC_CD, SM.AGNT_CD FROM TBL_SO_P SP INNER JOIN TBL_SO_M SM ON SP.TBL_SO_M_ID = SM.TBL_SO_M_ID LEFT JOIN TBL_MTRL_M PM ON SP.PROD_CD = PM.MTRL_CD LEFT JOIN TBL_AGENCY_M AG ON SM.AGNT_CD = AG.AGNT_CD LEFT JOIN TBL_LGST_DC_M DC ON SM.DC_CD = DC.DC_CD LEFT JOIN TBL_INST_PLAN_M IP ON SM.TBL_SO_M_ID = IP.TBL_SO_M_ID LEFT JOIN TBL_USER_M UM ON IP.TBL_USER_M_ID = UM.TBL_USER_M_ID WHERE 1=1 AND SM.SO_STAT_CD NOT IN ('0000', '1900') AND SP.USE_YN = 'Y' AND SM.SO_TYPE IN ('2000', '3200', '4200', '9903', '9906', '6000') AND (PM.EXCHANGE_RETURN_EXCLUDE_YN IS NULL OR PM.EXCHANGE_RETURN_EXCLUDE_YN = 'N') AND (AG.AGNT_NM IS NULL OR PATINDEX('%[가-힣]%', AG.AGNT_NM) > 0) -- 한글이 포함된 화주사명만 조회
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.DLVY_CNFM_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.DLVY_CNFM_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.AGNT_CD IN
#{agnt}
AND SM.DC_CD IN
#{dc}
AND SM.SO_NO IN
#{so}
AND SM.SO_TYPE IN
#{soType}
AND SM.ACPT_ER LIKE '%' + #{acptNm} + '%'
AND (SM.ACPT_TEL1 LIKE '%' + #{acptTel} + '%' OR SM.ACPT_TEL2 LIKE '%' + #{acptTel} + '%')
AND SP.PROD_CD IN
#{prod}
AND SP.PROD_NM LIKE '%' + #{prodNmSrch} + '%'
AND (SM.ADDR1 LIKE '%' + #{srchAddr} + '%' OR SM.ADDR2 LIKE '%' + #{srchAddr} + '%')
AND ISNULL(SP.YONGIN_INBOUNDED, 'N') = #{inboundStatus}
AND ISNULL(SP.AGENCY_OUTBOUNDED, 'N') = #{outboundStatus}
AND ISNULL(SP.IS_OUTBOUND_TARGET, 'Y') = #{outboundTarget}
ORDER BY SM.SAVE_TIME DESC

mapper.update:
UPDATE TBL_SO_P SET YONGIN_INBOUNDED = 'N', YONGIN_INBOUND_DT = NULL, YONGIN_INBOUND_USER = NULL, YONGIN_INBOUND_TIME = NULL, YONGIN_INBOUND_REMARK = CONCAT(ISNULL(YONGIN_INBOUND_REMARK, ''), CASE WHEN YONGIN_INBOUND_REMARK IS NOT NULL AND YONGIN_INBOUND_REMARK != '' THEN ' | ' ELSE '' END, '[되돌리기] ', #{revertRemark}, ' (', #{processUser}, ', ', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss'), ')'), UPDT_USER = #{processUser}, UPDT_TIME = GETDATE() WHERE TBL_SO_P_ID IN
#{id}
AND YONGIN_INBOUNDED = 'Y' -- 입고완료된 것만 되돌리기

UPDATE TBL_SO_P SET AGENCY_OUTBOUNDED = 'N', AGENCY_OUTBOUND_DT = NULL, AGENCY_OUTBOUND_USER = NULL, AGENCY_OUTBOUND_TIME = NULL, AGENCY_OUTBOUND_REMARK = CONCAT(ISNULL(AGENCY_OUTBOUND_REMARK, ''), CASE WHEN AGENCY_OUTBOUND_REMARK IS NOT NULL AND AGENCY_OUTBOUND_REMARK != '' THEN ' | ' ELSE '' END, '[되돌리기] ', #{revertRemark}, ' (', #{processUser}, ', ', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss'), ')'), UPDT_USER = #{processUser}, UPDT_TIME = GETDATE() WHERE TBL_SO_P_ID IN
#{id}
AND AGENCY_OUTBOUNDED = 'Y' -- 반출완료된 것만 되돌리기
